import{_ as i,c as e,a as s,o as n}from"./app-CEcM0piI.js";const a={};function l(r,t){return n(),e("div",null,t[0]||(t[0]=[s('<p>类似于键值对存储</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>SetInt/String/Float</td><td>把对应类型的数据存储在内存中，等游戏结束时unity会自动把数据存储到硬盘中，需要给出key值。只能存储这三个类型的数据，如果key相同会覆盖</td></tr><tr><td>Save</td><td>立刻把PlayerPrefs中的数据存储到硬盘</td></tr><tr><td>GetInt/String/Float</td><td>获取对应类型的值，如果没有则返回默认值，也可以手动设置默认值</td></tr><tr><td>HasKey</td><td>判断是否存在此key名的数据</td></tr><tr><td>DeletaKey</td><td>删除指定的key</td></tr><tr><td>DeleteAll</td><td>删除所有数据</td></tr></tbody></table><h3 id="存储位置" tabindex="-1"><a class="header-anchor" href="#存储位置"><span>存储位置</span></a></h3><p><strong>Windows</strong> /HKcu\\Software[公司名称][产品名称] 项下的注册表中 其中公司和产品名称是在&quot;ProjectSettings”中设置的名称。</p><p><strong>Android</strong> /data/data/包名/shared_prefs/pkg-name.xml</p><p><strong>IOS</strong> /Library/Preferences/[应用ID].plist</p><h1 id="json" tabindex="-1"><a class="header-anchor" href="#json"><span>JSON</span></a></h1><p>在unity中序列化和反序列化使用的类是JsonUtility</p><p><strong>将对象转化为json</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ToJson</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>在转化时浮点数会有精度误差</li><li>如果类中有自定义的类型那么该自定义类型的声明上面要加上<code>[Serializable]</code>特性</li><li>私有成员无法被序列化，要想序列化私有成员需要加上<code>[SerializeField]</code>特性</li><li>JsonUtility无法序列化字典</li><li>存储的null对象不会是null而是默认的数据</li></ul><p><strong>将json字符串反序列化</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>FromJson</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>读取时无法之间反序列化数组类型，只能使用一个对象包裹这个数组</p><ol><li>Jsonutlity是unity自带，LitJson是第三方需要引l用命名空间</li><li>Jsonutlity使用时自定义类需要加特性，LitJson不需要</li><li>Jsonutlity支持私有变量（加特性），LitJson不支持</li><li>Jsonutlity不支持字典，LitJson支持（但是键只能是字符串</li><li>Jsonutlity不能直接将数据反序列化为数据集合（数组字典）），itJson可以</li><li>Jsonutlity对自定义类不要求有无参构造，LitJson需要</li><li>Jsonutlity存储空对象时会存储默认值而不是null，LitJson会存nul1</li></ol>',15)]))}const o=i(a,[["render",l]]),h=JSON.parse('{"path":"/game/unity/4/","title":"4 数据持久化","lang":"zh-CN","frontmatter":{"title":"4 数据持久化","createTime":"2025/05/31 19:17:16","permalink":"/game/unity/4/"},"readingTime":{"minutes":1.68,"words":505},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/游戏/Unity/4 数据持久化.md","headers":[]}');export{o as comp,h as data};
